request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgId ?modelName ?origId ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  ?model bbo:name ?modelName .
  FILTER(CONTAINS(LCASE(STR(?modelName)), LCASE("Reisebro (Kopiee)")))
  OPTIONAL { ?org tai:organizationId ?orgId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgName ?model ?modelName ?origId ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .

  OPTIONAL { ?org bbo:name ?orgName . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model rdfs:label ?modelLabel . }

  FILTER(
    CONTAINS(LCASE(STR(?modelName)), LCASE("Reisebro")) ||
    CONTAINS(LCASE(STR(?modelLabel)), LCASE("Reisebro")) ||
    CONTAINS(LCASE(STR(?origId)), LCASE("Reisebro")) ||
    CONTAINS(LCASE(STR(?modelName)), LCASE("Kopiee")) ||
    CONTAINS(LCASE(STR(?modelLabel)), LCASE("Kopiee"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?created ?origId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    CONTAINS(LCASE(STR(?modelName)), LCASE("reise")) ||
    CONTAINS(LCASE(STR(?origId)), LCASE("reise"))
  )
}
LIMIT 25
